import React from 'react';
import NavItem from '../NavItem';
import * as C from './style'

function Nav({ onClick }) {

    return (
        <C.Container>
            <NavItem title='Pedidos' haddleNav/>
            <NavItem title='Produtos'/>
            <NavItem title='Pagamentos'/>
            <NavItem title='Controle Interno'/>
        </C.Container>
    )
}

export default Nav
